// Check if source should run based on cadence
const cadence = ($input.item.json.cadence || 'weekly').toLowerCase();
const day = new Date().getDay(); // 0=Sun, 1=Mon, ...
let shouldRun = false;

if (cadence === 'daily') {
  shouldRun = true;
} else if (cadence === '2x_weekly') {
  shouldRun = day === 1 || day === 4; // Mon, Thu
} else if (cadence === 'weekly') {
  shouldRun = day === 1; // Monday
} else if (cadence === 'monthly') {
  shouldRun = new Date().getDate() === 1; // 1st of month
}

return {json: {...$input.item.json, shouldRun}};

function simpleHash(str) {
  let h = 0;
  for (let i = 0; i < str.length; i++) { h = ((h << 5) - h) + str.charCodeAt(i); h |= 0; }
  return Math.abs(h).toString(36);
}

function extractTag(xml, tagName) {
  const openTag = "<" + tagName;
  const closeTag = "</" + tagName + ">";
  const startIdx = xml.indexOf(openTag);
  if (startIdx === -1) return "";
  const contentStart = xml.indexOf(">", startIdx) + 1;
  const endIdx = xml.indexOf(closeTag, contentStart);
  if (endIdx === -1) return "";
  let val = xml.substring(contentStart, endIdx);
  val = val.replace(/<!\\[CDATA\\[/g, "").replace(/\\]\\]>/g, "").trim();
  return val;
}

const sources = $input.all();
const out = [];

for (const srcItem of sources) {
  const src = srcItem.json;
  if (!src.feed_url) continue;
  try {
    const xml = await this.helpers.httpRequest({ timeout: 15000,
      method: "GET",
      url: src.feed_url,
      returnFullResponse: false,
      encoding: "utf-8",
    });
    const xmlStr = typeof xml === "string" ? xml : JSON.stringify(xml);
    const isAtom = xmlStr.includes("<entry");
    const tag = isAtom ? "entry" : "item";
    const closeTag = "</" + tag + ">";
    const openTag = "<" + tag;
    const parts = xmlStr.split(closeTag);
    let count = 0;
    for (const part of parts) {
      if (count >= 15) break;
      const idx = part.lastIndexOf(openTag);
      if (idx === -1) continue;
      const block = part.substring(idx);
      const title = extractTag(block, "title");
      let url = extractTag(block, "link");
      if (!url) {
        const hrefMatch = block.match(/href=\"([^\"]+)\"/);
        if (hrefMatch) url = hrefMatch[1];
      }
      if (!url) url = extractTag(block, "guid");
      const pubDate = extractTag(block, "pubDate") || extractTag(block, "published") || extractTag(block, "updated") || null;
      const desc = extractTag(block, "description") || extractTag(block, "content") || extractTag(block, "summary") || "";
      if (!title && !url) continue;
      const hash = simpleHash(title + url + (pubDate || ""));
      out.push({json: {
        source_id: src.source_id, source_name: src.name, source_type: src.source_type,
        channel: src.channel, tags: src.tags, domain_focus: src.domain_focus,
        title, url, published_at: pubDate,
        content_text: desc.substring(0, 20000),
        raw: {feed_url: src.feed_url, fetched_at: new Date().toISOString()},
        hash
      }});
      count++;
    }
  } catch(e) {
    out.push({json: {source_id: src.source_id, source_name: src.name, source_type: src.source_type, channel: "rss", skip: true, error: e.message}});
  }
}
return out.length > 0 ? out : [{json: {skip: true, error: "no items"}}];

