const item = $input.item.json;
if (item.skip) return {json: {...item, category: "category_formation", severity: 1, event_title: "Skipped", summary: "Source skipped", evidence_urls: "[]", is_candidate: true}};

const systemPrompt = "You are a B2B SaaS market analyst. Classify this content into a horizon event. Return ONLY valid JSON with: category (platform_shift|distribution_shift|buyer_risk|category_formation), severity (1-5), event_title (short), summary (2-3 sentences), evidence_urls (array of URLs).";
const userMsg = "Source: " + (item.source_name || "") + "\nTitle: " + (item.title || "") + "\nURL: " + (item.url || "") + "\nContent: " + (item.content_text || "").substring(0, 6000);

try {
  const data = await this.helpers.httpRequest({ timeout: 15000,
    method: "POST",
    url: "https://api.anthropic.com/v1/messages",
    headers: { "x-api-key": "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",
      "anthropic-version": "2023-06-01",
      "content-type": "application/json"
    },
    body: {
      model: "claude-3-5-haiku-20241022",
      max_tokens: 512,
      system: systemPrompt,
      messages: [{role: "user", content: userMsg}]
    },
    json: true,
  });

  if (data.error) {
    return {json: {source_id: item.source_id, item_id: item.item_id, source_type: item.source_type, category: "category_formation", severity: 1, event_title: item.title || "API Error", summary: "Anthropic error: " + (data.error.message || JSON.stringify(data.error)), evidence_urls: JSON.stringify([item.url || ""]), is_candidate: true}};
  }

  const text = data.content && data.content[0] ? data.content[0].text : "{}";
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  const parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
  return {json: {
    source_id: item.source_id, item_id: item.item_id, source_type: item.source_type,
    source_name: item.source_name, title: item.title, url: item.url,
    category: parsed.category || "category_formation",
    severity: parsed.severity || 1,
    event_title: parsed.event_title || parsed.title || item.title || "",
    summary: parsed.summary || "",
    evidence_urls: JSON.stringify(parsed.evidence_urls || [item.url || ""]),
    is_candidate: item.source_type !== "primary"
  }};
} catch(e) {
  return {json: {source_id: item.source_id, item_id: item.item_id, source_type: item.source_type, category: "category_formation", severity: 1, event_title: item.title || "Unknown", summary: "Classification failed: " + e.message, evidence_urls: JSON.stringify([item.url || ""]), is_candidate: true}};
}
